=== PR Comment 步骤 ===
      - name: Comment on PR for ERROR gates
        if: failure() && github.event_name == 'pull_request'
        uses: actions/github-script@v7
        with:
          script: |
            const fs = require('fs');
            const path = 'artifacts/testbot/pr_summary.json';

            if (!fs.existsSync(path)) {
              console.log('No summary file found');
              return;
            }

            const summary = JSON.parse(fs.readFileSync(path, 'utf8'));
            const gates = summary.gates || [];
            const errors = gates.filter(g => g.status === 'ERROR');

            if (errors.length === 0) {
              console.log('No ERROR gates found (WARN does not trigger comment)');
              return;
            }

            const body = `## 🔴 Testbot E2E Shadow Check Failed\n\n` +
              `**This is a shadow check and does not block merge.**\n\n` +
              `### Failed Gates\n\n` +
              errors.map(g => 
                `- **${g.name}**: ${g.message || 'Threshold exceeded'}\n` +
                  `  - Observed: \`${g.observed}\`\n` +
                  `  - Threshold: \`${g.threshold}\``
              ).join('\n\n') +
              `\n\n---\n*View full results in [workflow artifacts](${process.env.GITHUB_SERVER_URL}/${process.env.GITHUB_REPOSITORY}/actions/runs/${process.env.GITHUB_RUN_ID})*`;
